-- [ ObfusPro+ ]
local VBGIJ = bit32 or bit or error("ObfusPro+: Environment error");
local function GotnAk(akzsf)
    local idkjjrWz = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local iwHvc = string.gsub(akzsf, '[^' .. idkjjrWz .. ']', '')
    local WRpnkQP = {}
    for kVXL = 1, #iwHvc, 4 do
        local cec, SIh, Duf, asf = string.byte(iwHvc, kVXL, kVXL + 3)
        if not cec then break end
        local MOTm = string.find(idkjjrWz, string.char(cec)) - 1
        local zJjS = string.find(idkjjrWz, string.char(SIh)) - 1
        local jrky = Duf and string.find(idkjjrWz, string.char(Duf)) - 1 or 0
        local xYdg = asf and string.find(idkjjrWz, string.char(asf)) - 1 or 0
        local UiUM = MOTm * 262144 + zJjS * 4096 + jrky * 64 + xYdg
        local hTku = VBGIJ.band(VBGIJ.rshift(UiUM, 16), 255)
        table.insert(WRpnkQP, string.char(VBGIJ.bxor(hTku, 125)))
        if Duf and string.char(Duf) ~= '=' then
            hTku = VBGIJ.band(VBGIJ.rshift(UiUM, 8), 255)
            table.insert(WRpnkQP, string.char(VBGIJ.bxor(hTku, 125)))
        end
        if asf and string.char(asf) ~= '=' then
            hTku = VBGIJ.band(UiUM, 255)
            table.insert(WRpnkQP, string.char(VBGIJ.bxor(hTku, 125)))
        end
    end
    return table.concat(WRpnkQP)
end
